@Action
def set_product(userResponse: str) -> str:
    """Returns the product based on the service type."""
    try: 

      intent_map = {
          "mobile phones": "Mobile",
          "high speed internet" :"Internet",
          "television services":"TV",
          "business phone":"Business Phone",
          "home phone":"Home Phone",
          "home security":"Home Security",
          "advantage voice":"Advantage Voice"
      }

      if not userResponse:
          return "no value"

      userResponse = userResponse.strip().lower()
      intent = intent_map.get(userResponse, "technical-support-vague")
      return intent
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return "Code Block Error"

@Action
def set_saved_intent(service: str) -> str:
    """Returns the support intent name based on the service type."""
    try:

      intent_map = {
          "tv": "tv-support",
          "internet": "internet-support",
          "home phone": "home-phone-support",
          "business phone": "business-phone-support",
          "home security": "security-support",
          "mobile": "wireless-support",
          "advantage voice":"wireless-support"
      }

      if not service:
          return "no value"

      service = service.strip().lower()
      intent = intent_map.get(service, "technical-support-vague")
      productsMix=state["$session.params.productLabelsMixEn"]

      # 🔹 Additional logic for business phone
      if service == "business phone" and productsMix:
          if "wireless business phone" in productsMix.lower():
              intent = "wireless-support"

      return intent
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return "Code Block Error"

@Action
def check_saved_intent(counter:int) -> int:
    """Update counter based on intent and current value"""
    try:
      counter= int(counter)
      intent_map = state["$session.params.forcedSelfServIntent"]

      saved_intent = state["$session.params.savedIntent"]

      if intent_map.get(saved_intent) == True:
          if counter == 0:
              counter += 1
              return counter
          else:
              counter +=1
              return counter
      else:
          return counter
    except Exception as e:
        print(f"Something went wrong with the code block execution: {e}")
        return -3
